import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetimeimport urllib.parse# --- 1. AYARLAR VE GİZLİLİK ---st.set_page_config(page_title="Bostanlı Çözüm VIP", layout="wide", page_icon="🏫")hide_st_style = """            <style>            #MainMenu {visibility: hidden;}            footer {visibility: hidden;}            header {visibility: hidden;}            #stDecoration {display:none;}            [data-testid="stStatusWidget"] {visibility: hidden;}            .stDeployButton {display:none;}            button[title="Manage app"], [data-testid="stManageApp"], .viewerBadge_container__1QS1n {                display: none !important;                visibility: hidden !important;            }            </style>            """st.markdown(hide_st_style, unsafe_allow_html=True)# --- 2. GİRİŞ SİSTEMİ ---def check_password():    if "password_correct" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        with st.form("login_form"):            pwd = st.text_input("Giriş Şifresi", type="password")            if st.form_submit_button("Sisteme Giriş Yap"):                if pwd == "cozum35":                    st.session_state["password_correct"] = True                    st.rerun()                else:                    st.error("❌ Hatalı şifre.")        return False    return Trueif check_password():    # Bağlantı Ayarları    URL = "https://docs.google.com/spreadsheets/d/18BUCCdmATfgHJB1JkM9-T5lhoUaSXes55iMgHVRpOP4/edit?usp=sharing"    conn = st.connection("gsheets", type=GSheetsConnection)    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # --- YAN MENÜ ---    st.sidebar.title("🏫 Çözüm VIP")    sayfa = st.sidebar.radio("Menü:", ["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "📊 Kurucu Raporu"])    # --- 1. VELİ GÖRÜŞMELERİ ---    if sayfa == "📞 Veli Görüşmeleri":        st.header("📞 Veli Görüşme Kayıt")        try:            df_v = conn.read(spreadsheet=URL, worksheet="gorusmeler", ttl="0")        except:            df_v = pd.DataFrame(columns=["Tarih", "Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])                with st.form("v_form", clear_on_submit=True):            c1, c2 = st.columns(2)            v_ad = c1.text_input("Veli / Öğrenci Ad Soyad")            v_tel = c1.text_input("Telefon")            v_konu = c2.selectbox("Konu", ["Yeni Kayıt", "YKS", "LGS", "Rehberlik", "Taksit", "Diğer"])            v_durum = c2.selectbox("Durum", ["Beklemede", "Olumlu", "Kayıt Tamamlandı", "İptal"])            v_not = st.text_area("Notlar")            if st.form_submit_button("Kaydet"):                if v_ad and v_tel:                    new = pd.DataFrame([{"Tarih": datetime.now().strftime("%Y-%m-%d %H:%M"), "Ad Soyad": v_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not}])                    conn.update(spreadsheet=URL, worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                    st.success("✅ Kaydedildi")                    st.markdown(f'[(🟢 WhatsApp Mesajı At)]({wa_link(v_tel, "Görüşmemiz için teşekkürler.")})')    # --- 2. KASA İŞLEMLERİ ---    elif sayfa == "💰 Kasa İşlemleri":        st.header("💰 Kasa Giriş/Çıkış")        try:            df_k = conn.read(spreadsheet=URL, worksheet="kasa", ttl="0")        except:            df_k = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        with st.form("k_form", clear_on_submit=True):            k_tip = st.radio("Tür", ["Gelir (Tahsilat)", "Gider (Ödeme)"])            k_kat = st.selectbox("Kategori", ["Kayıt", "Kitap", "Kira", "Maaş", "Fatura", "Reklam", "Diğer"])            k_tutar = st.number_input("Tutar (TL)", min_value=0.0)            k_detay = st.text_input("Açıklama")            if st.form_submit_button("Kasaya İşle"):                new_k = pd.DataFrame([{"Tarih": datetime.now().strftime("%Y-%m-%d"), "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay}])                conn.update(spreadsheet=URL, worksheet="kasa", data=pd.concat([df_k, new_k], ignore_index=True))                st.success("💰 İşlem Tamam")    # --- 3. KURUCU RAPORU ---    elif sayfa == "📊 Kurucu Raporu":        st.header("📊 Günlük Özet")        t_sec = st.date_input("Tarih", datetime.now()).strftime("%Y-%m-%d")        try:            dv = conn.read(spreadsheet=URL, worksheet="gorusmeler", ttl="0")            dk = conn.read(spreadsheet=URL, worksheet="kasa", ttl="0")            dv_b = dv[dv['Tarih'].str.contains(t_sec, na=False)]            dk_b = dk[dk['Tarih'] == t_sec]            gelir = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']['Miktar'].astype(float).sum()            gider = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']['Miktar'].astype(float).sum()                        c1, c2, c3 = st.columns(3)            c1.metric("Görüşme", len(dv_b))            c2.metric("Gelir", f"{gelir:,.0f}")            c3.metric("Gider", f"{gider:,.0f}")                        txt = f"*📌 ÇÖZÜM RAPORU ({t_sec})*\n📞 Görüşme: {len(dv_b)}\n💰 Gelir: {gelir:,.0f} TL\n💸 Gider: {gider:,.0f} TL\n📈 Net: {gelir-gider:,.0f} TL"            st.info(txt)            st.markdown(f'[(📲 WhatsApp ile Gönder)]({wa_link("905492551912", txt)})')        except:            st.warning("Veri yüklenemedi, tabloyu kontrol edin.")